import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"36. Allowances Related To Overtime And On Call","description":"","frontmatter":{"title":"36. Allowances Related To Overtime And On Call","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","shift-work","rosters"]},"headers":[],"relativePath":"ebas/allied-health/allowances/36-allowances-related-to-overtime-and-on-call.md","filePath":"ebas/allied-health/allowances/36-allowances-related-to-overtime-and-on-call.md"}'),l={name:"ebas/allied-health/allowances/36-allowances-related-to-overtime-and-on-call.md"};function r(i,e,s,d,p,h){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_36-allowances-related-to-overtime-and-on-call" tabindex="-1">36. Allowances Related To Overtime And On Call <a class="header-anchor" href="#_36-allowances-related-to-overtime-and-on-call" aria-label="Permalink to &quot;36. Allowances Related To Overtime And On Call&quot;">​</a></h1><p><strong>36.1</strong> Meal Allowance</p><p><strong>(a)</strong> Meals Allowance Where Overtime Worked</p><p><strong>(i)</strong> Except as provided at subclause 36.1(b), an Employee who works overtime (including re-call) will be paid the meal allowance specified at A. more than one (1) hour of overtime after the end of a rostered shift; or B. more than two (2) hours overtime when they have been recalled to duty; and/or</p><p><strong>(ii)</strong> where the overtime or recall to duty exceeds four (4) hours, the Employee will be paid the meal allowance specified at <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a>, which is in addition to the meal allowance specified in subclause 36.1(a)(i)</p><p><strong>(b)</strong> Meal Allowance Where Overtime Worked – Exception The meal allowance provisions in subclause 36.1(a) above will not apply where a meal suitable to the Employee’s dietary requirements (for example, any allergy, religious or other dietary requirements) is supplied to the Employee at the Employer’s expense.</p><p><strong>36.2</strong> On-call Allowance</p><p><strong>(a)</strong> An on-call allowance of 2.5% of the AHP1 Grade 1, Year 1 rate will be paid to an Employee in respect of any 12 hour period or part thereof during which the Employee is on-call during the period commencing from the time of finishing ordinary duty on Monday and finishing at the termination of ordinary duty on Friday.</p><p><strong>(b)</strong> The allowance will be 5% of the AHP1, Grade 1, Year 1 rate in respect of any 12 hour period or part thereof during which the Employee is on-call during the period commencing from the time of termination of ordinary duty on Friday and finishing at the commencement of ordinary duty on Monday, or any public holiday or part thereof.</p><p><strong>36.3</strong> Telephone Allowance</p><p><strong>(a)</strong> Where the Employer requires an Employee to purchase, install and/or maintain a telephone, whether it be a land-line or a mobile phone, for the purposes of:</p><p><strong>(i)</strong> being on-call; and/or</p><p><strong>(ii)</strong> undertaking home visits (as described at subclause 105.9); the Employer will reimburse the purchase or installation costs and the subsequent rental charges or mobile phone charges on production of receipted accounts.</p><p><strong>(b)</strong> In lieu of paying an Employee the telephone allowance, an Employer may provide an Employee with a mobile phone for the purposes of being on-call and pay any costs and charges associated with it.</p><p>Plain language terms: OT, extra hours, double time.</p>',15)])])}const u=a(l,[["render",r]]);export{m as __pageData,u as default};
